# :name: scan_and_generate_requirements
# :description: Scan le code source pour détecter les imports externes et génère un fichier requirements.json
# :inputs: Aucun (travaille depuis le répertoire courant)
# :outputs: requirements.json contenant les imports détectés
# :filetype: script

import os
import re
import json
import ast
import sys

def scan_python_files(directory):
    python_files = []
    for root, _, files in os.walk(directory):
        for f in files:
            if f.endswith(".py"):
                python_files.append(os.path.join(root, f))
    return python_files

def extract_imports(file_path):
    imports = set()
    try:
        with open(file_path, "r", encoding="utf-8") as f:
            node = ast.parse(f.read(), filename=file_path)
            for stmt in node.body:
                if isinstance(stmt, ast.Import):
                    for alias in stmt.names:
                        imports.add(alias.name.split('.')[0])
                elif isinstance(stmt, ast.ImportFrom):
                    if stmt.module:
                        imports.add(stmt.module.split('.')[0])
    except Exception:
        pass
    return imports

def filter_stdlib_or_local(imports):
    # Modules internes que tu veux exclure explicitement
    internal_modules = {"project", "meta", "tools", "src", "services"}

    # Liste noire si besoin (ajoute les tiens)
    blacklist = {"__future__", "builtins", "typing"}

    # Modules natifs de Python
    stdlib_modules = set(sys.builtin_module_names)

    filtered = set()
    for imp in imports:
        if imp in blacklist or imp in stdlib_modules or imp in internal_modules:
            continue
        filtered.add(imp)
    return filtered

def generate_requirements_json(imports, output_file="requirements.json"):
    data = {
        "required_libraries": sorted(list(imports))
    }
    with open(output_file, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=2)
    print(f"✅ Fichier généré : {output_file}")

def main():
    print("🔍 Scan en cours...")
    all_imports = set()
    py_files = scan_python_files(".")
    for f in py_files:
        all_imports.update(extract_imports(f))
    filtered_imports = filter_stdlib_or_local(all_imports)
    generate_requirements_json(filtered_imports)

if __name__ == "__main__":
    main()
