from scan_and_do import scan_and_do

def execute_generate_requirements():
    def operation(filepath, content):
        import ast
        imports = set()
        try:
            node = ast.parse(content, filename=filepath)
            for stmt in node.body:
                if isinstance(stmt, ast.Import):
                    for alias in stmt.names:
                        imports.add(alias.name.split('.')[0])
                elif isinstance(stmt, ast.ImportFrom):
                    if stmt.module:
                        imports.add(stmt.module.split('.')[0])
        except Exception:
            pass
        return imports

    all_imports = scan_and_do(".", operation)

    import sys
    stdlib_modules = set(sys.builtin_module_names)
    blacklist = {"__future__", "typing", "builtins", "os", "sys"}

    def is_valid(lib):
        if lib in blacklist:
            return False
        if lib in stdlib_modules:
            return False
        return not lib.startswith("meta") and not lib.startswith("tools") and not lib.startswith("project")

    filtered = sorted(set(lib for lib in all_imports if is_valid(lib)))

    import json
    with open("requirements.json", "w") as f:
        json.dump({"required_libraries": filtered}, f, indent=2)

